const config = {
  "previewFeatures": [],
  "clientVersion": "7.8.0",
  "engineVersion": "3c6e192761c0362d496ed980de936e2f3cebcd3a",
  "activeProvider": "postgresql",
  "inlineSchema": "// Chisto.mk — Prisma schema\n// Civic environmental platform: pollution reporting, site lifecycle, cleanup events\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\nmodel User {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  firstName       String\n  lastName        String\n  email           String     @unique\n  phoneNumber     String     @unique\n  passwordHash    String\n  role            Role       @default(USER)\n  status          UserStatus @default(ACTIVE)\n  isPhoneVerified Boolean    @default(false)\n\n  pointsBalance             Int       @default(0)\n  totalPointsEarned         Int       @default(0)\n  totalPointsSpent          Int       @default(0)\n  reportCreditsAvailable    Int       @default(10)\n  reportCreditsSpentTotal   Int       @default(0)\n  reportEmergencyWindowDays Int       @default(7)\n  reportEmergencyUsedAt     DateTime?\n  lastActiveAt              DateTime?\n  avatarObjectKey           String?\n  avatarUpdatedAt           DateTime?\n\n  totpSecret     String? // Base32-encoded TOTP secret when 2FA enabled\n  mfaBackupCodes String[] @default([]) // Hashed backup codes\n\n  organizerCertifiedAt DateTime? // Set on organizer toolkit quiz pass; gates event creation\n\n  homeLatitude      Float?\n  homeLongitude     Float?\n  homeLocationLabel String?\n  homeLocationSetAt DateTime?\n\n  termsAcceptedAt   DateTime?\n  termsVersion      String?\n  privacyAcceptedAt DateTime?\n  deletedAt         DateTime?\n  showOnLeaderboard Boolean   @default(true)\n  /// Authoritative app UI locale for notifications (en | mk | sq).\n  locale            String?\n\n  reports                     Report[]                     @relation(\"ReporterReports\")\n  moderatedReports            Report[]                     @relation(\"ModeratorReports\")\n  adminNotifications          AdminNotification[]\n  pointTransactions           PointTransaction[]\n  coReportedReports           ReportCoReporter[]\n  sessions                    UserSession[]\n  auditLogs                   AuditLog[]\n  adminTempTokens             AdminTempToken[]\n  adminPendingMfa             AdminPendingMfa?\n  adminInvitesSent            AdminInvite[]                @relation(\"AdminInviteInviter\")\n  adminInviteAccepted         AdminInvite?                 @relation(\"AdminInviteAcceptedUser\")\n  adminEmailPreferences       AdminEmailPreference[]\n  adminEmailOutboxRows        AdminEmailOutbox[]           @relation(\"AdminEmailOutboxRecipient\")\n  broadcastCampaignsCreated   BroadcastCampaign[]          @relation(\"BroadcastCampaignCreator\")\n  siteVotes                   SiteVote[]\n  siteSaves                   SiteSave[]\n  siteComments                SiteComment[]\n  siteShareEvents             SiteShareEvent[]\n  siteShareLinks              SiteShareLink[]\n  siteCommentLikes            SiteCommentLike[]\n  feedState                   UserFeedState?\n  feedImpressions             FeedImpression[]\n  feedExperimentAssignments   FeedExperimentAssignment[]\n  deviceTokens                UserDeviceToken[]\n  userNotifications           UserNotification[]\n  notificationPreferences     UserNotificationPreference[]\n  organizedCleanupEvents      CleanupEvent[]               @relation(\"CleanupEventOrganizer\")\n  moderatedCleanupEvents      CleanupEvent[]               @relation(\"CleanupEventModerator\")\n  cleanupEventModerationNotes CleanupEventModerationNote[]\n  eventParticipations         EventParticipant[]\n  eventCheckIns               EventCheckIn[]\n  eventChatMessages           EventChatMessage[]           @relation(\"EventChatMessages\")\n  eventChatReadCursors        EventChatReadCursor[]        @relation(\"EventChatReadCursors\")\n  eventChatPinnedMessages     EventChatMessage[]           @relation(\"EventChatPinnedBy\")\n  eventChatMutes              EventChatMute[]              @relation(\"EventChatMutes\")\n  reportSubmitIdempotencyKeys ReportSubmitIdempotency[]\n  eventEvidencePhotosUploaded EventEvidencePhoto[]\n  routeSegmentsClaimed        EventRouteSegment[]          @relation(\"RouteSegmentClaims\")\n  checkInRiskSignals          CheckInRiskSignal[]\n  resolvedCheckInRiskSignals  CheckInRiskSignal[]          @relation(\"CheckInRiskSignalResolvedBy\")\n  archivedSites               Site[]                       @relation(\"SiteArchivedBy\")\n  passwordResetEmailCode      PasswordResetEmailCode?\n  blocksInitiated             UserBlock[]                  @relation(\"BlockBlocker\")\n  blocksReceived              UserBlock[]                  @relation(\"BlockBlocked\")\n  ugcReportsFiled             UgcContentReport[]           @relation(\"UgcReporter\")\n  activityEvents              UserActivityEvent[]\n  adminAlertRulesCreated      AdminAlertRule[]             @relation(\"AdminAlertRuleCreator\")\n\n  @@index([role])\n  @@index([status])\n}\n\n/// Per-user block list (App Store UGC requirement).\nmodel UserBlock {\n  id            String   @id @default(cuid())\n  blockerId     String\n  blockedUserId String\n  createdAt     DateTime @default(now())\n\n  blocker User @relation(\"BlockBlocker\", fields: [blockerId], references: [id], onDelete: Cascade)\n  blocked User @relation(\"BlockBlocked\", fields: [blockedUserId], references: [id], onDelete: Cascade)\n\n  @@unique([blockerId, blockedUserId])\n  @@index([blockerId])\n  @@index([blockedUserId])\n}\n\n/// Citizen-reported UGC (comments, chat, profiles) for admin moderation queue.\nmodel UgcContentReport {\n  id          String   @id @default(cuid())\n  reporterId  String\n  subjectType String\n  subjectId   String\n  reason      String\n  details     String?\n  status      String   @default(\"OPEN\")\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  reporter User @relation(\"UgcReporter\", fields: [reporterId], references: [id], onDelete: Cascade)\n\n  @@index([status, createdAt])\n  @@index([subjectType, subjectId])\n  @@index([reporterId])\n}\n\nmodel PasswordResetEmailCode {\n  id                  String    @id @default(cuid())\n  userId              String    @unique\n  codeHash            String\n  expiresAt           DateTime\n  attemptCount        Int       @default(0)\n  lastSentAt          DateTime?\n  sendCountInWindow   Int       @default(0)\n  sendWindowStartedAt DateTime?\n  createdAt           DateTime  @default(now())\n  updatedAt           DateTime  @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@index([expiresAt])\n}\n\nmodel UserSession {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  tokenId           String          @unique\n  refreshTokenHash  String\n  previousTokenHash String?\n  rotatedAt         DateTime?\n  deviceId          String?\n  deviceInfo        String?\n  ipAddress         String?\n  lastSeenAt        DateTime?\n  platform          DevicePlatform?\n  appVersion        String?\n  deviceModel       String?\n  osVersion         String?\n  country           String?\n  city              String?\n  expiresAt         DateTime\n  revokedAt         DateTime?\n  rememberMe        Boolean         @default(true)\n\n  activityEvents UserActivityEvent[]\n\n  @@index([userId, revokedAt])\n  @@index([userId, deviceId])\n  @@index([expiresAt])\n  @@index([lastSeenAt])\n}\n\nenum UserActivityEventType {\n  LOGIN\n  LOGOUT\n  APP_OPENED\n  SCREEN_VIEW\n  REPORT_CREATED\n  REPORT_SUBMITTED\n  EVENT_JOINED\n  CHECK_IN\n}\n\nmodel UserActivityEvent {\n  id         String                @id @default(cuid())\n  userId     String\n  user       User                  @relation(fields: [userId], references: [id], onDelete: Cascade)\n  sessionId  String?\n  session    UserSession?          @relation(fields: [sessionId], references: [id], onDelete: SetNull)\n  deviceId   String?\n  type       UserActivityEventType\n  screen     String?\n  metadata   Json?\n  platform   DevicePlatform?\n  appVersion String?\n  occurredAt DateTime              @default(now())\n  createdAt  DateTime              @default(now())\n\n  @@index([userId, occurredAt(sort: Desc)])\n  @@index([occurredAt(sort: Desc)])\n  @@index([type, occurredAt(sort: Desc)])\n}\n\nmodel DailyActiveStat {\n  id               String   @id @default(cuid())\n  date             DateTime @unique @db.Date\n  dau              Int      @default(0)\n  wau              Int      @default(0)\n  mau              Int      @default(0)\n  peakConcurrent   Int      @default(0)\n  avgConcurrent    Float    @default(0)\n  sessionsStarted  Int      @default(0)\n  reportsSubmitted Int      @default(0)\n  newRegistrations Int      @default(0)\n  createdAt        DateTime @default(now())\n  updatedAt        DateTime @updatedAt\n}\n\nenum AdminAlertMetric {\n  CONCURRENT\n  TRAFFIC_SPIKE\n  ERROR_RATE\n  REPORT_ACTIVITY\n  API_DEGRADATION\n}\n\nenum AdminAlertComparator {\n  GT\n  GTE\n}\n\nmodel AdminAlertRule {\n  id              String               @id @default(cuid())\n  metric          AdminAlertMetric\n  comparator      AdminAlertComparator @default(GT)\n  threshold       Float\n  windowSeconds   Int                  @default(300)\n  enabled         Boolean              @default(true)\n  lastTriggeredAt DateTime?\n  createdById     String?\n  createdBy       User?                @relation(\"AdminAlertRuleCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n  createdAt       DateTime             @default(now())\n  updatedAt       DateTime             @updatedAt\n\n  @@index([enabled])\n  @@index([metric])\n}\n\nmodel PhoneOtp {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  phoneNumber         String\n  /// Legacy plaintext code; new rows use codeHash only.\n  code                String    @default(\"\")\n  codeHash            String?\n  expiresAt           DateTime\n  attemptCount        Int       @default(0)\n  lastSentAt          DateTime?\n  sendCountInWindow   Int       @default(0)\n  sendWindowStartedAt DateTime?\n\n  @@unique([phoneNumber])\n  @@index([expiresAt])\n}\n\nmodel LoginFailure {\n  id            String   @id @default(cuid())\n  phoneNumber   String   @unique\n  firstFailedAt DateTime\n  attemptCount  Int\n\n  @@index([phoneNumber])\n}\n\nmodel AdminLoginFailure {\n  id            String   @id @default(cuid())\n  email         String   @unique\n  firstFailedAt DateTime\n  attemptCount  Int\n\n  @@index([email])\n}\n\nmodel AdminTempToken {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  tokenHash String   @unique // bcrypt hash of the temp token\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  email     String\n  expiresAt DateTime\n\n  @@index([expiresAt])\n  @@index([userId])\n}\n\nenum AdminInviteStatus {\n  PENDING\n  ACCEPTED\n  REVOKED\n  EXPIRED\n}\n\nmodel AdminInvite {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  email          String\n  firstName      String\n  lastName       String\n  role           Role\n  tokenHash      String            @unique\n  mfaSecret      String?\n  status         AdminInviteStatus @default(PENDING)\n  invitedById    String\n  invitedBy      User              @relation(\"AdminInviteInviter\", fields: [invitedById], references: [id], onDelete: Cascade)\n  acceptedUserId String?           @unique\n  acceptedUser   User?             @relation(\"AdminInviteAcceptedUser\", fields: [acceptedUserId], references: [id], onDelete: SetNull)\n  expiresAt      DateTime\n  acceptedAt     DateTime?\n  revokedAt      DateTime?\n  attemptCount   Int               @default(0)\n\n  @@index([email])\n  @@index([status])\n}\n\nenum AdminModerationCategory {\n  NEW_REPORT\n  EVENT_PENDING\n  UGC_REPORT\n  CHECKIN_RISK\n}\n\nmodel AdminEmailPreference {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userId   String\n  user     User                    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  category AdminModerationCategory\n  enabled  Boolean\n\n  @@unique([userId, category])\n  @@index([userId])\n}\n\nenum AdminEmailOutboxStatus {\n  PENDING\n  SENT\n  FAILED\n}\n\nmodel AdminEmailOutbox {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  recipientUserId String\n  recipientUser   User                    @relation(\"AdminEmailOutboxRecipient\", fields: [recipientUserId], references: [id], onDelete: Cascade)\n  recipientEmail  String\n  category        AdminModerationCategory\n  templateId      String\n  payload         Json\n  status          AdminEmailOutboxStatus  @default(PENDING)\n  attempts        Int                     @default(0)\n  maxAttempts     Int                     @default(5)\n  nextAttemptAt   DateTime?\n  processingAt    DateTime?\n  leaseOwner      String?\n  lastAttemptAt   DateTime?\n  lastError       String?\n  idempotencyKey  String                  @unique\n\n  @@index([status, nextAttemptAt, processingAt])\n  @@index([createdAt])\n}\n\nmodel AdminPendingMfa {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  secret    String\n  expiresAt DateTime\n\n  @@unique([userId])\n  @@index([expiresAt])\n}\n\nenum Role {\n  USER\n  SUPPORT\n  ADMIN\n  SUPER_ADMIN\n}\n\nenum UserStatus {\n  ACTIVE\n  SUSPENDED\n  DELETED\n}\n\n// Admin notifications for console activity\nmodel AdminNotification {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  title     String\n  message   String\n  timeLabel String\n  tone      AdminNotificationTone\n  category  AdminNotificationCategory\n  isUnread  Boolean                   @default(true)\n  href      String?\n\n  /// Stable key for localized templates (e.g. `reports.submitted.new_site`). Title/message remain populated for legacy clients.\n  messageTemplateKey    String?\n  messageTemplateParams Json?\n\n  @@index([userId, createdAt])\n  @@index([category, createdAt])\n}\n\nenum AdminNotificationTone {\n  success\n  warning\n  info\n  neutral\n}\n\nenum AdminNotificationCategory {\n  reports\n  system\n  analytics\n}\n\nmodel PointTransaction {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  delta         Int\n  balanceAfter  Int\n  reasonCode    String\n  referenceType String @default(\"\")\n  referenceId   String @default(\"\")\n  metadata      Json?\n\n  @@unique([userId, referenceType, referenceId, reasonCode], map: \"point_transaction_user_ref_reason_key\")\n  @@index([userId, createdAt])\n  @@index([reasonCode])\n  @@index([referenceType, referenceId])\n}\n\nenum ReportCleanupEffort {\n  ONE_TO_TWO\n  THREE_TO_FIVE\n  SIX_TO_TEN\n  TEN_PLUS\n  NOT_SURE\n}\n\n// Canonical pollution/report site\nmodel Site {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  latitude          Float\n  longitude         Float\n  /// Reverse-geocoded or user-confirmed place line from mobile (not the report narrative).\n  address           String?\n  description       String?\n  searchVector      Unsupported(\"tsvector\")?\n  geo               Unsupported(\"geography(Point,4326)\")?\n  status            SiteStatus                            @default(REPORTED)\n  isArchivedByAdmin Boolean                               @default(false)\n  archivedAt        DateTime?\n  archivedById      String?\n  archivedBy        User?                                 @relation(\"SiteArchivedBy\", fields: [archivedById], references: [id], onDelete: SetNull)\n  archiveReason     String?\n  upvotesCount      Int                                   @default(0)\n  commentsCount     Int                                   @default(0)\n  savesCount        Int                                   @default(0)\n  sharesCount       Int                                   @default(0)\n\n  reports         Report[]\n  events          CleanupEvent[]\n  votes           SiteVote[]\n  saves           SiteSave[]\n  comments        SiteComment[]\n  shareEvents     SiteShareEvent[]\n  shareLinks      SiteShareLink[]\n  featureSnapshot SiteFeatureSnapshot?\n  feedImpressions FeedImpression[]\n  mapProjection   MapSiteProjection?\n  historyEntries  SiteHistoryEntry[]\n\n  /// Earliest APPROVED report with media — canonical image for feed, map, and detail.\n  heroReportId String? @unique\n  heroReport   Report? @relation(\"SiteHeroReport\", fields: [heroReportId], references: [id], onDelete: SetNull)\n\n  @@index([status])\n  @@index([isArchivedByAdmin])\n  @@index([status, isArchivedByAdmin, updatedAt])\n  @@index([latitude, longitude])\n  /// Map queries often filter by status plus lat/lng bounding box.\n  @@index([status, latitude, longitude])\n  @@index([createdAt])\n  /// Feed retrievers commonly filter by status and order by createdAt.\n  @@index([status, createdAt])\n  /// Engagement retriever ordering support.\n  @@index([status, sharesCount, upvotesCount, commentsCount, createdAt])\n  @@index([archivedById])\n}\n\nenum SiteStatus {\n  REPORTED\n  VERIFIED\n  CLEANUP_SCHEDULED\n  IN_PROGRESS\n  CLEANED\n  DISPUTED\n}\n\n/// Append-only chronological log for pollution site lifecycle (mobile timeline + admin).\nmodel SiteHistoryEntry {\n  id             String               @id @default(cuid())\n  siteId         String\n  site           Site                 @relation(fields: [siteId], references: [id], onDelete: Cascade)\n  kind           SiteHistoryEntryKind\n  occurredAt     DateTime             @default(now())\n  fromStatus     SiteStatus?\n  toStatus       SiteStatus?\n  reportId       String?\n  cleanupEventId String?\n  actorUserId    String?\n  actorRole      String?\n  note           String?\n  metadata       Json?\n  createdAt      DateTime             @default(now())\n\n  @@index([siteId, occurredAt(sort: Desc)])\n  @@index([reportId])\n  @@index([cleanupEventId])\n}\n\nenum SiteHistoryEntryKind {\n  SITE_CREATED\n  REPORT_SUBMITTED\n  REPORT_APPROVED\n  REPORT_REJECTED\n  REPORT_MERGED\n  STATUS_CHANGED\n  CLEANUP_EVENT_SCHEDULED\n  CLEANUP_EVENT_STARTED\n  CLEANUP_EVENT_COMPLETED\n  CLEANUP_EVENT_CANCELLED\n  ARCHIVED_BY_ADMIN\n  UNARCHIVED_BY_ADMIN\n  ADMIN_NOTE\n}\n\n// User-submitted pollution report\nmodel Report {\n  id           String   @id @default(cuid())\n  createdAt    DateTime @default(now())\n  reportNumber String?  @unique // Human-friendly ID: CH-000001, set by DB trigger on insert\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  reporterId String?\n  reporter   User?   @relation(\"ReporterReports\", fields: [reporterId], references: [id], onDelete: SetNull)\n\n  /// Short headline shown in lists and moderation (required on new submissions).\n  title         String\n  description   String?\n  mediaUrls     String[]             @default([])\n  category      String?\n  severity      Int?\n  cleanupEffort ReportCleanupEffort?\n\n  status           ReportStatus @default(NEW)\n  moderatedAt      DateTime?\n  moderationReason String?\n  moderatedById    String?\n  moderatedBy      User?        @relation(\"ModeratorReports\", fields: [moderatedById], references: [id], onDelete: SetNull)\n\n  // Optional link to a primary report this one is considered a potential duplicate of\n  potentialDuplicateOfId String?\n  potentialDuplicateOf   Report?  @relation(\"ReportPotentialDuplicate\", fields: [potentialDuplicateOfId], references: [id])\n  potentialDuplicates    Report[] @relation(\"ReportPotentialDuplicate\")\n\n  /// Duplicate child reports merged into this canonical report (moderation merge).\n  mergedDuplicateChildCount Int @default(0)\n\n  coReporters           ReportCoReporter[]\n  submitIdempotencyKeys ReportSubmitIdempotency[]\n  heroForSite           Site?                     @relation(\"SiteHeroReport\")\n\n  @@index([siteId])\n  @@index([siteId, createdAt(sort: Desc)])\n  @@index([reporterId])\n  @@index([status])\n  @@index([potentialDuplicateOfId])\n  @@index([moderatedById])\n}\n\nenum ReportStatus {\n  NEW\n  IN_REVIEW\n  APPROVED\n  DELETED\n}\n\n// Additional reporters attached to an existing report\nmodel ReportCoReporter {\n  id         String   @id @default(cuid())\n  createdAt  DateTime @default(now())\n  /// When this person filed their report (duplicate submission or merge source time).\n  reportedAt DateTime\n\n  reportId String\n  report   Report @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  @@unique([reportId, userId])\n  @@index([userId])\n}\n\n/// Client-supplied key (UUID) so duplicate POST /reports retries return the same report without double spend.\nmodel ReportSubmitIdempotency {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  key      String\n  reportId String\n  report   Report @relation(fields: [reportId], references: [id], onDelete: Cascade)\n\n  @@unique([userId, key])\n  @@index([createdAt])\n  @@index([reportId])\n}\n\n/// Async-capable outbox for post-commit report side effects (merge notifications, audit, S3, WS).\nenum ReportSideEffectKind {\n  MERGE_DUPLICATE_POST\n  MODERATION_STATUS_POST\n}\n\nenum ReportSideEffectStatus {\n  PENDING\n  PROCESSING\n  COMPLETED\n  FAILED\n}\n\nmodel ReportSideEffect {\n  id           String                 @id @default(cuid())\n  createdAt    DateTime               @default(now())\n  updatedAt    DateTime               @updatedAt\n  kind         ReportSideEffectKind\n  status       ReportSideEffectStatus @default(PENDING)\n  payload      Json\n  attempts     Int                    @default(0)\n  lastError    String?\n  processedAt  DateTime?\n  processingAt DateTime?\n  leaseOwner   String?\n\n  @@index([status, createdAt])\n}\n\nmodel SystemConfig {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  key   String @unique\n  value String\n\n  @@index([key])\n}\n\nenum BroadcastCampaignStatus {\n  DRAFT\n  SCHEDULED\n  SENT\n  CANCELLED\n}\n\nenum BroadcastAudience {\n  ALL\n  ACTIVE\n  AREA\n  USERS\n}\n\nmodel BroadcastCampaign {\n  id        String   @id\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  title           String\n  body            String\n  type            String                  @default(\"SYSTEM\")\n  deeplink        String?\n  audience        BroadcastAudience\n  audienceUserIds String[]                @default([])\n  status          BroadcastCampaignStatus @default(DRAFT)\n  scheduledAt     DateTime?\n  sentAt          DateTime?\n  sentCount       Int?\n\n  createdById String?\n  createdBy   User?   @relation(\"BroadcastCampaignCreator\", fields: [createdById], references: [id], onDelete: SetNull)\n\n  @@index([status, scheduledAt])\n  @@index([createdAt(sort: Desc)])\n}\n\nmodel FeatureFlag {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  key      String  @unique\n  enabled  Boolean @default(false)\n  metadata Json?\n\n  @@index([key])\n}\n\n/// Postmark bounce/complaint/manual suppression — blocks outbound mail to the address.\nmodel EmailSuppression {\n  email     String   @id\n  reason    String\n  source    String   @default(\"postmark\")\n  payload   Json?\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([createdAt])\n}\n\nmodel AuditLog {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  actorId      String?\n  actor        User?   @relation(fields: [actorId], references: [id], onDelete: SetNull)\n  action       String\n  resourceType String\n  resourceId   String?\n  metadata     Json?\n  ipAddress    String?\n\n  @@index([actorId, createdAt])\n  @@index([resourceType, createdAt])\n  @@index([action])\n}\n\nenum CleanupEventStatus {\n  PENDING // Awaiting admin approval (user-created)\n  APPROVED // Visible to users, can be joined\n  DECLINED // Rejected by admin\n}\n\n/// Citizen-facing lifecycle (aligned with mobile EcoEventStatus).\nenum EcoEventLifecycleStatus {\n  UPCOMING\n  IN_PROGRESS\n  COMPLETED\n  CANCELLED\n}\n\nenum EcoEventCategory {\n  GENERAL_CLEANUP\n  RIVER_AND_LAKE\n  TREE_AND_GREEN\n  RECYCLING_DRIVE\n  HAZARDOUS_REMOVAL\n  AWARENESS_AND_EDUCATION\n  OTHER\n}\n\nenum EcoCleanupScale {\n  SMALL\n  MEDIUM\n  LARGE\n  MASSIVE\n}\n\nenum EcoEventDifficulty {\n  EASY\n  MODERATE\n  HARD\n}\n\n// Cleanup event at a site\nmodel CleanupEvent {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  title       String\n  description String           @db.Text\n  category    EcoEventCategory @default(GENERAL_CLEANUP)\n\n  scheduledAt             DateTime\n  endAt                   DateTime?\n  /// When set to the same instant as [endAt], the organizer \"cleanup ending soon\" push was sent for that end time. Cleared when [endAt] changes (extension).\n  endSoonNotifiedForEndAt DateTime?\n  completedAt             DateTime?\n\n  /// Moderation (admin approval for user-created events).\n  status CleanupEventStatus @default(APPROVED)\n\n  /// Admin who last approved or declined (null while pending or after return-to-pending).\n  moderatedById String?\n  moderatedBy   User?     @relation(\"CleanupEventModerator\", fields: [moderatedById], references: [id], onDelete: SetNull)\n  moderatedAt   DateTime?\n  /// Persisted decline reason (also mirrored in audit metadata).\n  declineReason String?   @db.Text\n\n  /// Lifecycle shown in the mobile app when event is APPROVED.\n  lifecycleStatus EcoEventLifecycleStatus @default(UPCOMING)\n\n  organizerId String?\n  organizer   User?   @relation(\"CleanupEventOrganizer\", fields: [organizerId], references: [id], onDelete: SetNull)\n\n  participantCount Int @default(0)\n\n  gear            String[]            @default([])\n  scale           EcoCleanupScale?\n  difficulty      EcoEventDifficulty?\n  afterImageKeys  String[]            @default([])\n  maxParticipants Int?\n\n  /// Rotates when organizer opens check-in or taps rotate; invalidates old QR tokens.\n  checkInSessionId String?\n  checkInOpen      Boolean @default(false)\n  /// Denormalized count of [EventCheckIn] rows for this event.\n  checkedInCount   Int     @default(0)\n\n  participants       EventParticipant[]\n  checkIns           EventCheckIn[]\n  checkInRedemptions EventCheckInRedemption[]\n  chatMessages       EventChatMessage[]\n  chatReadCursors    EventChatReadCursor[]\n  chatMutes          EventChatMute[]\n  liveMetric         EventLiveMetric?\n  evidencePhotos     EventEvidencePhoto[]\n  routeSegments      EventRouteSegment[]\n  checkInRiskSignals CheckInRiskSignal[]\n  moderationNotes    CleanupEventModerationNote[]\n\n  /// PostgreSQL `tsvector` for ranked full-text search (generated column + GIN index in migration).\n  /// Declared as [Unsupported] so Prisma Client does not expose it and migrations stay aligned with the DB.\n  searchVector Unsupported(\"tsvector\")?\n\n  /// RFC 5545 RRULE string (e.g. FREQ=WEEKLY;COUNT=8;BYDAY=SA).\n  /// Null for non-recurring events.\n  recurrenceRule String?\n\n  /// References the first event in a recurring series. Null for standalone/parent events.\n  parentEventId  String?\n  parentEvent    CleanupEvent?  @relation(\"RecurrenceSeries\", fields: [parentEventId], references: [id], onDelete: SetNull)\n  seriesChildren CleanupEvent[] @relation(\"RecurrenceSeries\")\n\n  /// 0-based index within its series (0 = original/parent). Null for non-recurring.\n  recurrenceIndex Int?\n\n  @@index([siteId])\n  @@index([scheduledAt])\n  @@index([siteId, scheduledAt])\n  @@index([status])\n  @@index([lifecycleStatus, scheduledAt])\n  @@index([lifecycleStatus, endAt])\n  @@index([organizerId])\n  @@index([parentEventId])\n  @@index([moderatedById])\n}\n\n/// Internal admin-only notes on a cleanup event (not visible to organizers).\nmodel CleanupEventModerationNote {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  authorId            String?\n  author              User?   @relation(fields: [authorId], references: [id], onDelete: SetNull)\n  authorEmailSnapshot String?\n\n  body String @db.Text\n\n  @@index([eventId, createdAt])\n  @@index([authorId])\n}\n\nenum EventChatMessageType {\n  TEXT\n  SYSTEM\n  IMAGE\n  LOCATION\n  VIDEO\n  AUDIO\n  FILE\n}\n\nmodel EventParticipant {\n  id       String   @id @default(cuid())\n  joinedAt DateTime @default(now())\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  reminderEnabled Boolean   @default(false)\n  reminderAt      DateTime?\n\n  @@unique([eventId, userId])\n  @@index([eventId, joinedAt])\n  @@index([userId])\n}\n\n/// Text or system message in an event participant chat (organizer + joiners).\nmodel EventChatMessage {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  authorId String?\n  author   User?   @relation(\"EventChatMessages\", fields: [authorId], references: [id], onDelete: SetNull)\n\n  body String @db.Text\n\n  replyToId String?\n  replyTo   EventChatMessage?  @relation(\"ChatReplies\", fields: [replyToId], references: [id], onDelete: SetNull)\n  replies   EventChatMessage[] @relation(\"ChatReplies\")\n\n  deletedAt DateTime?\n\n  editedAt DateTime?\n\n  isPinned   Boolean   @default(false)\n  pinnedAt   DateTime?\n  pinnedById String?\n  pinnedBy   User?     @relation(\"EventChatPinnedBy\", fields: [pinnedById], references: [id], onDelete: SetNull)\n\n  messageType   EventChatMessageType @default(TEXT)\n  systemPayload Json?\n\n  locationLat   Float?\n  locationLng   Float?\n  locationLabel String?\n\n  bodyEncrypted Boolean @default(false)\n\n  /// Client-generated UUID for idempotent sends (POST retry / offline flush).\n  clientMessageId String?\n\n  attachments EventChatAttachment[]\n\n  readCursorsLastRead EventChatReadCursor[] @relation(\"ReadCursorLastMessage\")\n\n  @@unique([eventId, clientMessageId])\n  @@index([eventId, createdAt])\n  @@index([authorId])\n  @@index([eventId, isPinned, pinnedAt])\n  @@index([replyToId])\n  @@index([pinnedById])\n}\n\nmodel EventChatAttachment {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  messageId String\n  message   EventChatMessage @relation(fields: [messageId], references: [id], onDelete: Cascade)\n\n  url          String\n  mimeType     String\n  fileName     String\n  sizeBytes    Int\n  width        Int?\n  height       Int?\n  duration     Int?\n  thumbnailUrl String?\n\n  @@index([messageId])\n}\n\n/// Per-user mute for event chat push notifications (SSE still delivers).\nmodel EventChatMute {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(\"EventChatMutes\", fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([eventId, userId])\n  @@index([userId])\n}\n\n/// Per-user read position for event chat unread counts.\nmodel EventChatReadCursor {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(\"EventChatReadCursors\", fields: [userId], references: [id], onDelete: Cascade)\n\n  lastReadMessageId String?\n  lastReadMessage   EventChatMessage? @relation(\"ReadCursorLastMessage\", fields: [lastReadMessageId], references: [id], onDelete: SetNull)\n\n  @@unique([eventId, userId])\n  @@index([userId])\n  @@index([lastReadMessageId])\n}\n\n/// Attendee check-in at an event (registered user or manual guest list).\nmodel EventCheckIn {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  /// `u:<userId>` for app users, `g:<slug>` for manual guest rows (normalized name).\n  dedupeKey String\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  guestDisplayName String?\n\n  checkedInAt DateTime @default(now())\n\n  @@unique([eventId, dedupeKey])\n  @@index([eventId, checkedInAt])\n  @@index([userId])\n}\n\n/// Single-use QR token ids (jti) — prevents screenshot replay across different users.\nmodel EventCheckInRedemption {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  jti String @unique\n\n  @@index([eventId])\n}\n\n/// Denormalized organizer-reported live counters (pulse); aggregates also read from [CleanupEvent].\nmodel EventLiveMetric {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  eventId String       @unique\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  reportedBagsCollected Int @default(0)\n}\n\nenum EventEvidenceKind {\n  BEFORE\n  AFTER\n  FIELD\n}\n\nmodel EventEvidencePhoto {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  kind         EventEvidenceKind\n  objectKey    String\n  caption      String?\n  uploadedById String?\n  uploadedBy   User?             @relation(fields: [uploadedById], references: [id], onDelete: SetNull)\n\n  @@index([eventId, kind, createdAt])\n  @@index([uploadedById])\n}\n\nenum RouteSegmentStatus {\n  OPEN\n  CLAIMED\n  COMPLETED\n}\n\nmodel EventRouteSegment {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  sortOrder Int\n  label     String?\n  latitude  Float\n  longitude Float\n\n  status RouteSegmentStatus @default(OPEN)\n\n  claimedByUserId String?\n  claimedBy       User?     @relation(\"RouteSegmentClaims\", fields: [claimedByUserId], references: [id], onDelete: SetNull)\n  claimedAt       DateTime?\n  completedAt     DateTime?\n\n  @@index([eventId, sortOrder])\n  @@index([claimedByUserId])\n}\n\nenum CheckInRiskSignalType {\n  FAR_FROM_SITE\n}\n\nmodel CheckInRiskSignal {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  expiresAt DateTime\n\n  eventId String\n  event   CleanupEvent @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  signalType CheckInRiskSignalType\n  metadata   Json?\n\n  resolvedAt       DateTime?\n  resolvedByUserId String?\n  resolvedBy       User?     @relation(\"CheckInRiskSignalResolvedBy\", fields: [resolvedByUserId], references: [id], onDelete: SetNull)\n  /**\n   * Admin action when resolved: resolve | dismiss\n   */\n  resolutionAction String?\n\n  @@index([eventId, createdAt])\n  @@index([userId, createdAt])\n  @@index([expiresAt])\n  @@index([resolvedAt])\n}\n\nmodel SiteVote {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  @@unique([siteId, userId])\n  @@index([userId, createdAt])\n  @@index([siteId, createdAt])\n}\n\nmodel SiteSave {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([siteId, userId])\n  @@index([userId, createdAt])\n  @@index([siteId, createdAt])\n}\n\nmodel SiteComment {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  authorId String?\n  author   User?   @relation(fields: [authorId], references: [id], onDelete: SetNull)\n\n  parentId String?\n  parent   SiteComment?      @relation(\"SiteCommentReplies\", fields: [parentId], references: [id], onDelete: Cascade)\n  replies  SiteComment[]     @relation(\"SiteCommentReplies\")\n  likes    SiteCommentLike[]\n\n  body       String\n  isDeleted  Boolean @default(false)\n  likesCount Int     @default(0)\n\n  @@index([siteId, createdAt])\n  @@index([siteId, parentId, createdAt])\n  @@index([authorId, createdAt])\n}\n\nmodel SiteCommentLike {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  commentId String\n  comment   SiteComment @relation(fields: [commentId], references: [id], onDelete: Cascade)\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([commentId, userId])\n  @@index([commentId, createdAt])\n  @@index([userId, createdAt])\n}\n\nenum SiteShareChannel {\n  native\n  link\n  whatsapp\n  facebook\n  x\n  other\n}\n\nmodel SiteShareEvent {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  userId String?\n  user   User?   @relation(fields: [userId], references: [id], onDelete: SetNull)\n\n  channel SiteShareChannel @default(native)\n\n  @@unique([siteId, userId])\n  @@index([siteId, createdAt])\n  @@index([userId, createdAt])\n}\n\nenum SiteShareAttributionEventType {\n  CLICK\n  OPEN\n}\n\nenum SiteShareAttributionSource {\n  WEB\n  APP\n  OTHER\n}\n\nmodel SiteShareLink {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  cid       String    @unique\n  expiresAt DateTime\n  countedAt DateTime?\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  sharedByUserId String?\n  sharedByUser   User?   @relation(fields: [sharedByUserId], references: [id], onDelete: SetNull)\n\n  channel SiteShareChannel @default(native)\n\n  attributionEvents SiteShareAttributionEvent[]\n\n  @@index([siteId, createdAt])\n  @@index([sharedByUserId, createdAt])\n  @@index([expiresAt])\n}\n\nmodel SiteShareAttributionEvent {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  shareLinkId String\n  shareLink   SiteShareLink @relation(fields: [shareLinkId], references: [id], onDelete: Cascade)\n\n  eventType SiteShareAttributionEventType\n  source    SiteShareAttributionSource    @default(OTHER)\n  dedupeKey String\n\n  ipHash         String?\n  userAgentHash  String?\n  openedByUserId String?\n\n  @@unique([shareLinkId, eventType, dedupeKey])\n  @@index([shareLinkId, createdAt])\n  @@index([eventType, createdAt])\n}\n\nmodel UserFeedState {\n  userId             String    @id\n  mutedCategoryIds   String[]  @default([])\n  hiddenSiteIds      String[]  @default([])\n  followReporterIds  String[]  @default([])\n  engagementProfile  Json?\n  recencyDecayFactor Float     @default(0)\n  lastFeedAt         DateTime?\n  updatedAt          DateTime  @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n}\n\nmodel SiteFeatureSnapshot {\n  siteId          String    @id\n  velocity1h      Float     @default(0)\n  velocity6h      Float     @default(0)\n  velocity24h     Float     @default(0)\n  discussionRatio Float     @default(0)\n  intentRatio     Float     @default(0)\n  qualityScore    Float     @default(0)\n  freshnessHours  Float     @default(0)\n  severityIndex   Float     @default(0)\n  verifiedAgeDays Int       @default(0)\n  lastReportAt    DateTime?\n  denormHash      String    @default(\"\")\n  updatedAt       DateTime  @updatedAt\n\n  site Site @relation(fields: [siteId], references: [id], onDelete: Cascade)\n}\n\nmodel FeedImpression {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  siteId String\n  site   Site   @relation(fields: [siteId], references: [id], onDelete: Cascade)\n\n  variant  String\n  position Int?\n  dwellMs  Int?\n  engaged  Boolean @default(false)\n\n  @@index([userId, createdAt])\n  @@index([siteId, createdAt])\n}\n\nmodel FeedExperimentAssignment {\n  userId        String\n  experimentKey String\n  variant       String\n  assignedAt    DateTime @default(now())\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@id([userId, experimentKey])\n}\n\nenum DevicePlatform {\n  IOS\n  ANDROID\n}\n\nmodel UserDeviceToken {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  token        String         @unique\n  platform     DevicePlatform\n  appVersion   String?\n  locale       String?\n  lastSeenAt   DateTime       @default(now())\n  revokedAt    DateTime?\n  failureCount Int            @default(0)\n\n  @@index([userId, revokedAt])\n  @@index([token])\n}\n\nenum NotificationType {\n  SITE_UPDATE\n  REPORT_STATUS\n  UPVOTE\n  COMMENT\n  NEARBY_REPORT\n  CLEANUP_EVENT\n  EVENT_CHAT\n  SYSTEM\n  ACHIEVEMENT\n  WELCOME\n}\n\nmodel UserNotification {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  title      String\n  body       String\n  type       NotificationType\n  isRead     Boolean          @default(false)\n  data       Json?\n  sentAt     DateTime?\n  openedAt   DateTime?\n  threadKey  String?\n  groupKey   String?\n  archivedAt DateTime?\n\n  @@index([userId, isRead, createdAt])\n  @@index([userId, createdAt])\n  @@index([userId, type])\n  @@index([userId, groupKey, createdAt])\n  @@index([userId, archivedAt, createdAt])\n}\n\nmodel UserNotificationPreference {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  type               NotificationType\n  muted              Boolean          @default(false)\n  mutedUntil         DateTime?\n  /// Minutes from local midnight (0–1439) when quiet hours start.\n  quietHoursStart    Int?\n  quietHoursEnd      Int?\n  quietHoursTimezone String?\n  /// When true, transactional email for this notification type is suppressed for the user.\n  emailMuted         Boolean          @default(false)\n  emailMutedUntil    DateTime?\n\n  @@unique([userId, type])\n  @@index([userId, muted])\n}\n\nmodel NotificationOutbox {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userNotificationId String\n  deviceToken        String\n  payload            Json\n  attempts           Int       @default(0)\n  nextRetryAt        DateTime?\n  processingAt       DateTime?\n  leaseOwner         String?\n  lastAttemptAt      DateTime?\n  lastErrorCode      String?\n  lastErrorMessage   String?\n  deliveredAt        DateTime?\n  failedPermanently  Boolean   @default(false)\n  idempotencyKey     String    @unique\n\n  @@index([deliveredAt, failedPermanently, attempts])\n  @@index([processingAt, nextRetryAt])\n  @@index([createdAt])\n}\n\nmodel EmailOutbox {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  userId            String\n  templateId        String\n  payload           Json\n  attempts          Int       @default(0)\n  nextRetryAt       DateTime?\n  processingAt      DateTime?\n  leaseOwner        String?\n  lastAttemptAt     DateTime?\n  lastError         String?\n  deliveredAt       DateTime?\n  failedPermanently Boolean   @default(false)\n  idempotencyKey    String    @unique\n\n  @@index([deliveredAt, failedPermanently, attempts])\n  @@index([processingAt, nextRetryAt])\n}\n\nmodel MapSiteProjection {\n  siteId                  String                                @id\n  site                    Site                                  @relation(fields: [siteId], references: [id], onDelete: Cascade)\n  latitude                Float\n  longitude               Float\n  geo                     Unsupported(\"geography(Point,4326)\")?\n  status                  SiteStatus\n  address                 String?\n  description             String?\n  thumbnailUrl            String?\n  pollutionCategory       String?\n  latestReportTitle       String?\n  latestReportDescription String?\n  latestReportNumber      String?\n  reportCount             Int                                   @default(0)\n  upvotesCount            Int                                   @default(0)\n  commentsCount           Int                                   @default(0)\n  savesCount              Int                                   @default(0)\n  sharesCount             Int                                   @default(0)\n  latestReportAt          DateTime?\n  siteCreatedAt           DateTime\n  siteUpdatedAt           DateTime\n  projectedAt             DateTime                              @default(now())\n  isHot                   Boolean                               @default(true)\n  isArchivedByAdmin       Boolean                               @default(false)\n  archivedAt              DateTime?\n\n  @@index([isHot, status, latitude, longitude])\n  @@index([isArchivedByAdmin, status, latitude, longitude])\n  @@index([isHot, siteUpdatedAt])\n  @@index([status, siteCreatedAt])\n}\n\nenum MapEventOutboxStatus {\n  PENDING\n  DISPATCHED\n  FAILED\n}\n\nmodel MapEventOutbox {\n  id           String               @id @default(cuid())\n  createdAt    DateTime             @default(now())\n  updatedAt    DateTime             @updatedAt\n  eventId      String               @unique\n  siteId       String\n  eventType    String\n  payload      Json\n  status       MapEventOutboxStatus @default(PENDING)\n  attempts     Int                  @default(0)\n  lastError    String?\n  dispatchedAt DateTime?\n  leaseOwner   String?\n  processingAt DateTime?\n\n  @@index([status, createdAt])\n  @@index([siteId, createdAt])\n  @@index([processingAt])\n}\n\nmodel MapCdnPurgeLog {\n  id           String   @id\n  createdAt    DateTime @default(now())\n  provider     String\n  status       String\n  keys         Json\n  errorMessage String?\n\n  @@index([createdAt])\n}\n\n/// Records client-supplied job ids for idempotent admin bulk mutations (e.g. bulk approve/decline).\nmodel AdminMutationIdempotency {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n\n  actorUserId String\n  purpose     String\n  clientJobId String\n\n  @@unique([actorUserId, purpose, clientJobId])\n  @@index([createdAt])\n  @@map(\"admin_mutation_idempotency\")\n}\n"
}

